INSERT INTO assinaturas (empresa_id, bubble_unique_id, asaas_customer_id, asaas_descricao, asaas_parcela, asaas_evento, asaas_status, asaas_valor_recebido, mensalidade, plano, recorrencia, total_pago, ticket_medio, data_criacao_assinatura, data_acesso_ate, data_cancelamento, ativo, cancelado, motivo_cancelamento, tipo_motivo_cancelamento, nome_assinante, contato_assinante, cidade_assinante, uf_assinante, observacoes, forma_entrada, cupom_ativado, d_token, created_at, updated_at, created_by)
VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('Eltz Celulares') LIMIT 1), '1756314659180x375636108696831400', 'cus_000065715476', NULL, NULL, NULL, NULL, NULL, NULL, 'Essencial', 'Mensal', 2480.0, 124.0, '2023-10-09T00:00:00', '2025-06-10T00:00:00', '2025-05-29T00:00:00', true, false, 'Cliente solicitou o cancelamento do plano por meio do suporte falando que não está usando a plataforma. Entrei em contato com ele tentando entender o motivo do cancelamento, falei da importância dele como cliente para nós, por ele estar conosco desde o começo, perguntei o motivo da falta de uso, se era um caso externo ou se era falta de alguma ferramenta etc, ele respondeu "Só não estou usando. Gostaria de cancelar.", falei pra ele que seguiria com a solicitação, e ressaltei a importância de termos esse feedback para melhoria e acrescentei que ele poderia mandar áudio se fosse mais fácil, ele seguiu sem responder sobre e apenas agradeceu.  Verifiquei o uso dele na planilha e a última vez que possui registro de uso foi dia 08/01/2025, sendo que, a última vez que ele contatou nosso suporte por dia 21/01/2025. Nesse contato, não houve dúvidas sem responder, era apenas um caso simples de dúvida, nada que motivasse a falta de uso.', 'Não se adaptou', 'NATANAEL ELTZ MARQUES DIAS', '19998582936', 'Hortolândia', 'SP', NULL, NULL, NULL, NULL, '2025-08-27T14:10:00', '2025-09-04T17:45:00', NULL);
