INSERT INTO assinaturas (empresa_id, bubble_unique_id, asaas_customer_id, asaas_descricao, asaas_parcela, asaas_evento, asaas_status, asaas_valor_recebido, mensalidade, plano, recorrencia, total_pago, ticket_medio, data_criacao_assinatura, data_acesso_ate, data_cancelamento, ativo, cancelado, motivo_cancelamento, tipo_motivo_cancelamento, nome_assinante, contato_assinante, cidade_assinante, uf_assinante, observacoes, forma_entrada, cupom_ativado, d_token, created_at, updated_at, created_by)
VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('APPLE ERA') LIMIT 1), '1756314660423x254899400544772900', 'cus_000072873090', NULL, NULL, NULL, NULL, NULL, NULL, 'Essencial', 'Mensal', 2431.0, 122.0, '2023-11-23T00:00:00', '2025-07-17T00:00:00', '2025-07-02T00:00:00', true, false, 'A loja contratou a TenFront por meio da Maisa, porém, no mês passado a Mari Chopek entrou em contato com a gente para fazer a troca das informações da conta do sistema porque a Maisa vendeu a loja pra ela. Desde então, o suporte ofereceu vários treinamentos pra ela, que recusou, porém, ela tinha algumas dúvidas e contatava o suporte. Quando solicitou o cancelamento, ela falou que ama o atendimento, mas não consegue usar o sistema, e o irmão dela fez um pra ela e ela se adaptou.  Eu insisti em realizar um treinamento com ela também e inclusive falei sobre o plano gerencial, que possui relatórios mais estratégicos que podem ser usados em tráfego pago e assistência técnica, já que olhei no Instagram da loja e vi que eles trabalham também com assistência. Ela respondeu de forma mais incisiva falando que quer cancelar mesmo.', 'Não se adaptou', 'Marianne Chopek do Nascimento', '45991418465', 'Toledo', 'PR', NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2025-09-04T16:24:00', NULL);
