INSERT INTO assinaturas (empresa_id, bubble_unique_id, asaas_customer_id, asaas_descricao, asaas_parcela, asaas_evento, asaas_status, asaas_valor_recebido, mensalidade, plano, recorrencia, total_pago, ticket_medio, data_criacao_assinatura, data_acesso_ate, data_cancelamento, ativo, cancelado, motivo_cancelamento, tipo_motivo_cancelamento, nome_assinante, contato_assinante, cidade_assinante, uf_assinante, observacoes, forma_entrada, cupom_ativado, d_token, created_at, updated_at, created_by)
VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('Jorge Pereira Alves Neto') LIMIT 1), '1756314671999x513330903826786200', 'cus_000113622603', NULL, NULL, NULL, NULL, NULL, NULL, 'Estratégia', 'Mensal', 647.5, 216.0, '2025-03-23T00:00:00', '2025-06-09T00:00:00', '2025-06-09T00:00:00', true, false, 'Cliente fechou o plano gerencial conosco na CBM com a promessa do CRM. Assim que lançado, o CRM foi apresentado pra ele e ele fechou o plano estratégia para poder usar.  Ele estava com as expectativas muito altas para o CRM e o não atendeu as expectativas dele, ele falou que tá faltando muita coisa que ele precisa e que, futuramente, quando melhorar, podemos voltar a conversar.  Acredito que podemos seguir com o cancelamento dele por conta da necessidade que ele já tinha avisando no fechamento sobre o CRM e, na próxima versão, podemos entrar em contato com ele novamente. Assim, mantemos um bom relacionamento com ele. Também é válido destacar que a noiva dele possui outra loja, então quando atendermos as expectativas dele, temos mais oportunidades ao redor.', 'CRM', 'Jorge Pereira Alves Neto', '12991693096', NULL, NULL, NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2025-09-04T17:37:00', NULL);
