INSERT INTO assinaturas (empresa_id, bubble_unique_id, asaas_customer_id, asaas_descricao, asaas_parcela, asaas_evento, asaas_status, asaas_valor_recebido, mensalidade, plano, recorrencia, total_pago, ticket_medio, data_criacao_assinatura, data_acesso_ate, data_cancelamento, ativo, cancelado, motivo_cancelamento, tipo_motivo_cancelamento, nome_assinante, contato_assinante, cidade_assinante, uf_assinante, observacoes, forma_entrada, cupom_ativado, d_token, created_at, updated_at, created_by)
VALUES ((SELECT id FROM empresas WHERE trim(nome) = trim('GRCell Alvorada') LIMIT 1), '1756314673224x237907189695725440', 'cus_000121355193', NULL, NULL, NULL, NULL, NULL, NULL, 'Gerencial', 'Mensal', 239.0, 239.0, '2025-06-03T00:00:00', '2025-07-04T00:00:00', '2025-07-01T00:00:00', true, false, 'Cliente se recusou várias vezes a realizar o treinamento em horário comercial, ele queria fazer após às 19h. Tentei agendar com ele diversas vezes e quando ele parou de me retornar, pedi para o suporte dar mais atenção para ele e tentar novamente o treinamento, sem sucesso (no treinamento), porém ele sempre foi muito engajado com o suporte, em relação às dúvidas. Suas maiores reclamações foram de não ser opcional pedir o CPF do cliente e a impressão de OS somente em formato A4 - ele utiliza impressora térmica. Cliente sempre teve suas dúvidas sanadas e realizou a migração conosco, entregue antes do prazo. Perguntando pra ele qual o motivo do cancelamento, ele falou que achou muito complexa, não gostou muito.  Comentei com ele sobre o treinamento, que ele facilitaria esse processo e ofereci pra ele uma chamada para falarmos sobre as pontuações dele e encontramos uma solução. Ele não aceitou e preferiu realizar o cancelamento.', 'Não se adaptou', 'Rian José dos Santos Batista', '31993766376', NULL, NULL, NULL, NULL, NULL, NULL, '2025-08-27T14:11:00', '2025-09-04T17:07:00', NULL);
